svg.script:
(function () {
  "use strict";

  const DURATION_MS = 5600;
  const LIFT = {
    "headAngle": -10.5,
    "headCapPath": "M64 155.69 C60.01 87.41 114 46.68 187 46.68 C257.67 47.08 309.54 87.75 310 155.69 C310 219.71 257 258.71 187 258.71 C117 258.71 64 219.71 64 155.69Z",
    "cheekPath": "M65 173.38 C72.74 174.53 117.92 182.82 129.5 182.94 C139.43 183.04 156.35 175.93 161.51 174.4 C166.67 172.87 175.61 167.67 179.65 168.03 C183.69 168.39 195.34 176.32 200.8 177.86 C206.25 179.4 221.58 183.47 232.72 183.01 C245.7 182.47 299.85 174.54 309 173.38 C328.64 195.34 332.95 225.08 303.09 243.88 C270.8 267.13 103.2 267.13 70.91 243.88 C37.38 225.5 42.48 194.92 65 173.38Z",
    "faceTransform": "translate(-10.04 18.94) translate(173.61 172) skewX(0) scale(1 1) translate(-173.61 -172)",
    "blushTransform": "translate(-10.04 19) translate(173.61 172) skewX(0) scale(1 1) translate(-173.61 -172)",
    "mouthInset": 19
  };
  const SINK = {
    "headAngle": -12.5,
    "headCapPath": "M64 155.9 C58.79 87.37 113.4 46.58 187 46.58 C257.56 47.1 309.4 87.82 310 155.9 C310 220.14 257 259.14 187 259.14 C117 259.14 64 220.14 64 155.9Z",
    "cheekPath": "M65 174.94 C72.44 176.09 115.76 184.38 126.98 184.5 C136.6 184.6 153.4 177.49 158.51 175.96 C163.61 174.43 172.55 169.23 176.6 169.59 C180.64 169.95 192.34 177.88 197.86 179.42 C203.39 180.96 218.86 185.03 230.3 184.57 C243.63 184.03 299.56 176.1 309 174.94 C327.92 196.74 332.02 225.31 303.1 243.72 C270.91 267.38 103.09 267.38 70.9 243.72 C37.19 225.84 42.32 196.21 65 174.94Z",
    "faceTransform": "translate(-13.1 20.31) translate(169.53 172) skewX(0) scale(1 1) translate(-169.53 -172)",
    "blushTransform": "translate(-13.1 20.39) translate(169.53 172) skewX(0) scale(1 1) translate(-169.53 -172)",
    "mouthInset": 22
  };
  const MOUTH_LENGTH = 40.59;
  const MOUTH_GAP = 64.59;
  const NUM_RE = /-?\d*\.?\d+(?:e[-+]?\d+)?/gi;

  const root = document.documentElement;
  const headPose = document.getElementById("sleep-head-pose-layer");
  const headCap = headPose && headPose.querySelector("#head-cap-fill");
  const cheek = headPose && headPose.querySelector("#cheek-muzzle-fill");
  const blushClip = document.getElementById("sleep-face-blush-clip-path");
  const face = headPose && headPose.querySelector("#face-layer");
  const blush = document.getElementById("sleep-face-blush-transform");
  const mouthLeft = headPose && headPose.querySelector("#mouth-left");
  const mouthRight = headPose && headPose.querySelector("#mouth-right");
  const bodyBreath = document.getElementById("sleep-body-breath-layer");
  const leftPngHandPose = document.getElementById("sleep-left-png-hand-pose");
  const rightPngHandPose = document.getElementById("sleep-right-png-hand-pose");
  const tieBreath = document.getElementById("sleep-tie-breath-layer");
  const tieKnot = document.getElementById("sleep-tie-knot-pose");
  const tieBlade = document.getElementById("sleep-tie-blade-pose");

  function clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  function fract(value) {
    return value - Math.floor(value);
  }


  function lerp(a, b, t) {
    return a + (b - a) * t;
  }

  function fmt(value) {
    const rounded = Math.round(value * 100) / 100;
    return rounded.toFixed(2).replace(/\.?0+$/, "");
  }

  function fmtFine(value) {
    const rounded = Math.round(value * 10000) / 10000;
    return rounded.toFixed(4).replace(/\.?0+$/, "");
  }

  function numbers(value) {
    return (value.match(NUM_RE) || []).map(Number);
  }

  function mixNumbersInString(a, b, t) {
    const bNums = numbers(b);
    let index = 0;
    return a.replace(NUM_RE, (match) => fmt(lerp(Number(match), bNums[index++], t)));
  }

  function easeBreath(linear) {
    return (1 - Math.cos(linear * Math.PI * 2)) / 2;
  }

  function render(breath, linearPhase) {
    const t = clamp(breath, 0, 1);
    const phase = linearPhase == null ? 0 : fract(linearPhase);
    const angle = lerp(LIFT.headAngle, SINK.headAngle, t);

    if (bodyBreath) {
      const bodyScaleX = 1 + 0.024 * t;
      const bodyScaleY = 1 - 0.018 * t;
      const bodyY = 1.6 * t;
      bodyBreath.setAttribute("transform", "translate(187 322) translate(0 " + fmtFine(bodyY) + ") scale(" + fmtFine(bodyScaleX) + " " + fmtFine(bodyScaleY) + ") translate(-187 -322)");
    }

    if (leftPngHandPose) leftPngHandPose.setAttribute("transform", "rotate(" + fmtFine(-1.6 * t) + " 142 253)");
    if (rightPngHandPose) rightPngHandPose.setAttribute("transform", "rotate(" + fmtFine(1.45 * t) + " 232 253)");

    const tieLag = easeBreath(fract(phase + 0.08));
    if (tieBreath) {
      const tieY = 0.95 * t;
      const tieRotate = lerp(-0.45, 0.8, tieLag);
      tieBreath.setAttribute("transform", "translate(0 " + fmt(tieY) + ") rotate(" + fmt(tieRotate) + " 187 263)");
    }
    if (tieKnot) {
      tieKnot.setAttribute("transform", "translate(-4 6.5) rotate(" + fmt(-10.5 - 0.55 * t + 0.18 * tieLag) + " 34 14)");
    }
    if (tieBlade) {
      tieBlade.setAttribute("transform", "translate(-3 8) translate(34 24) rotate(" + fmt(-7 - 1.25 * tieLag + 0.25 * t) + ") skewX(" + fmt(-5 - 0.6 * tieLag) + ") scale(" + fmt(0.98 + 0.004 * t) + " " + fmt(1.04 + 0.006 * t) + ") translate(-34 -24)");
    }

    if (headPose) headPose.setAttribute("transform", "translate(-7 7) rotate(" + fmt(angle) + " 187 244)");
    if (headCap) headCap.setAttribute("d", mixNumbersInString(LIFT.headCapPath, SINK.headCapPath, t));
    const cheekPath = mixNumbersInString(LIFT.cheekPath, SINK.cheekPath, t);
    if (cheek) cheek.setAttribute("d", cheekPath);
    if (blushClip) blushClip.setAttribute("d", cheekPath);
    if (face) face.setAttribute("transform", mixNumbersInString(LIFT.faceTransform, SINK.faceTransform, t));
    if (blush) blush.setAttribute("transform", mixNumbersInString(LIFT.blushTransform, SINK.blushTransform, t));

    const mouthInset = lerp(LIFT.mouthInset, SINK.mouthInset, t);
    const visibleMouth = Math.max(0.1, MOUTH_LENGTH - mouthInset);
    const mouthDash = fmt(visibleMouth) + " " + fmt(MOUTH_GAP);
    if (mouthLeft) mouthLeft.setAttribute("stroke-dasharray", mouthDash);
    if (mouthRight) mouthRight.setAttribute("stroke-dasharray", mouthDash);

    root.setAttribute("data-sleep-breath", fmt(t));
    root.setAttribute("data-sleep-phase", fmt(phase));
  }

  let startTime = null;

  function tick(now) {
    if (startTime === null) startTime = now;
    const phase = ((now - startTime) % DURATION_MS) / DURATION_MS;
    render(easeBreath(phase), phase);
    requestAnimationFrame(tick);
  }

  const reducedMotion = typeof matchMedia === "function" && matchMedia("(prefers-reduced-motion: reduce)").matches;
  render(0, 0);
  if (!reducedMotion && typeof requestAnimationFrame === "function") requestAnimationFrame(tick);
}());
